-- Approved product combinations imported from solutions/*.json
-- These rows are the recommendation catalog used by calculate-residential.

create table if not exists approved_solutions (
  id uuid primary key default gen_random_uuid(),
  source_file text not null,
  solution_code text not null,
  schema_version text not null default '1.0',
  inverter_model text not null,
  inverter_quantity int not null check (inverter_quantity > 0),
  battery_ports_used int not null check (battery_ports_used > 0),
  nominal_voltage_v int not null check (nominal_voltage_v > 0),
  rated_power_w int not null check (rated_power_w > 0),
  peak_power_w int not null check (peak_power_w >= rated_power_w),
  grid_topology text not null check (grid_topology in ('1p_220V', '3p_220V', '3p_380V')),
  battery_model text not null,
  battery_topology text not null check (battery_topology in ('HV', 'LV')),
  battery_quantity int not null check (battery_quantity > 0),
  battery_power_w int not null check (battery_power_w > 0),
  available_energy_wh int not null check (available_energy_wh > 0),
  accessories jsonb not null default '[]'::jsonb,
  comments jsonb not null default '[]'::jsonb,
  raw_solution jsonb not null,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  unique (source_file, solution_code)
);

alter table approved_solutions enable row level security;

create policy "public read approved_solutions"
  on approved_solutions for select
  using (active);

create index if not exists approved_solutions_match_idx
  on approved_solutions (active, grid_topology, battery_topology, rated_power_w, available_energy_wh);

create index if not exists approved_solutions_models_idx
  on approved_solutions (inverter_model, battery_model);

